class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # Compute the XOR of all elements in nums
        current_xor = 0
        for num in nums:
            current_xor ^= num

        # Compute the XOR difference between current_xor and k
        xor_diff = current_xor ^ k

        # Count the number of bits that need to be flipped
        # This is the number of set bits in xor_diff
        return bin(xor_diff).count('1')
